async (params, browser) => {
  // Search GitHub repos
  await browser.open('https://github.com/search')

  // Wait for search results
  await browser.waitForSelector('[data-testid=\'results-list\'], .search-results, .repo-list', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract search results
  const result = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[data-testid="results-list"] > div, .repo-list-item, .search-title a'); if (items.length === 0) { const links = document.querySelectorAll('a[href]'); const repoLinks = []; for (const l of links) { const href = l.getAttribute('href') || ''; if (href.match(/^\/[^/]+\/[^/]+$/) && !href.startsWith('/search') && !href.startsWith('/settings') && !href.startsWith('/features') && l.closest('[data-testid="results-list"], .repo-list, main')) { repoLinks.push(l); } } for (let i = 0; i < Math.min(repoLinks.length, 10); i++) { const link = repoLinks[i]; const container = link.closest('div, li, article'); const descEl = container ? container.querySelector('p, .mb-1, span.Text-sc') : null; results.push({ name: link.textContent.trim().replace(/\s+/g, ''), description: descEl ? descEl.textContent.trim().substring(0, 200) : '', language: '', stars: '', url: 'https://github.com' + link.getAttribute('href') }); } } else { for (let i = 0; i < Math.min(items.length, 10); i++) { const item = items[i]; const linkEl = item.querySelector('a[href*="/"]') || item; const descEl = item.querySelector('p, .mb-1'); const langEl = item.querySelector('[itemprop="programmingLanguage"], span.repo-language-color + span'); const starsEl = item.querySelector('a[href*="/stargazers"], .mr-3'); const href = linkEl.getAttribute ? linkEl.getAttribute('href') : ''; results.push({ name: href ? href.replace(/^\//, '') : linkEl.textContent.trim().replace(/\s+/g, ''), description: descEl ? descEl.textContent.trim().substring(0, 200) : '', language: langEl ? langEl.textContent.trim() : '', stars: starsEl ? starsEl.textContent.trim() : '', url: href ? 'https://github.com' + href : '' }); } } return { result_count: results.length, results: results }`)

  return result
}
